// HasApps applies the HasEdge predicate on the "apps" edge.
func HasApps() predicate.ClientSource {
	return predicate.ClientSource(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, AppsTable, AppsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasAppsWith applies the HasEdge predicate on the "apps" edge with a given conditions (other predicates).
func HasAppsWith(preds ...predicate.ClientSourceApp) predicate.ClientSource {
	return predicate.ClientSource(func(s *sql.Selector) {
		step := newAppsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ClientSource) predicate.ClientSource {
	return predicate.ClientSource(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ClientSource) predicate.ClientSource {
	return predicate.ClientSource(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ClientSource) predicate.ClientSource {
	return predicate.ClientSource(sql.NotPredicates(p))
}
